from dataclasses import dataclass, field
from typing import Optional

COMPETENCY_DOMAINS = [
    "prompt_engineering",
    "output_evaluation",
    "workflow_integration",
    "ai_risk_compliance",
    "data_literacy",
    "model_selection",
    "ethics_bias_awareness",
    "change_leadership",
]

# Role-specific target levels (0-3 scale)
ROLE_TARGETS: dict[str, dict[str, int]] = {
    "knowledge_worker": {
        "prompt_engineering": 2, "output_evaluation": 2,
        "workflow_integration": 1, "ai_risk_compliance": 2,
        "data_literacy": 1, "model_selection": 0,
