@dataclass
class EmployeeSkillAssessment:
    employee_id: str
    role: str
    business_unit: str
    # Self-assessed current proficiency per domain (0-3)
    self_assessed: dict[str, int] = field(default_factory=dict)
    # Manager-observed (optional corroboration)
    manager_observed: dict[str, Optional[int]] = field(default_factory=dict)
    # Assessment source weight: self-report alone has calibration_factor applied
    calibration_factor: float = 0.85  # self-reports tend to be 15% inflated

    def calibrated_level(self, domain: str) -> float:
        """Use manager-observed if available; otherwise calibrate self-report."""
        if domain in self.manager_observed and self.manager_observed[domain] is not None:
            return self.manager_observed[domain]
        return self.self_assessed.get(domain, 0) * self.calibration_factor

    def gap(self, domain: str) -> float:
        target = ROLE_TARGETS.get(self.role, {}).get(domain, 0)
        current = self.calibrated_level(domain)
        return max(0.0, target - current)

    def gap_summary(self) -> dict[str, float]:
        return {
            domain: round(self.gap(domain), 2)
            for domain in COMPETENCY_DOMAINS
            if domain in ROLE_TARGETS.get(self.role, {})
        }

    def priority_gaps(self, threshold: float = 1.0) -> list[tuple[str, float]]:
        """Return domains with gap >= threshold, sorted by gap size descending."""
        gaps = self.gap_summary()
        return sorted(
            [(d, g) for d, g in gaps.items() if g >= threshold],
            key=lambda x: -x[1]
        )

