from dataclasses import dataclass, field
from statistics import mean

@dataclass
class RoleGapAnalysis:
    role: str
    assessments: list[EmployeeSkillAssessment]

    def average_gap(self, domain: str) -> float:
        gaps = [a.gap(domain) for a in self.assessments
                if domain in ROLE_TARGETS.get(a.role, {})]
        return mean(gaps) if gaps else 0.0

    def gap_map(self) -> dict[str, float]:
        targets = ROLE_TARGETS.get(self.role, {})
        return {
            domain: round(self.average_gap(domain), 2)
            for domain in targets
        }

    def gap_size_label(self, gap: float) -> str:
        if gap >= 1.5: return "LARGE"
        if gap >= 0.75: return "MEDIUM"
        return "SMALL"

    def priority_interventions(self) -> list[dict]:
        gap_map = self.gap_map()
        results = []
        for domain, gap in sorted(gap_map.items(), key=lambda x: -x[1]):
            if gap >= 0.75:
                results.append({
                    "domain": domain,
                    "avg_gap": gap,
                    "size": self.gap_size_label(gap),
                    "employees_affected": sum(
                        1 for a in self.assessments if a.gap(domain) >= 0.75
                    ),
                })
        return results

