from dataclasses import dataclass, field
from typing import Optional

@dataclass
class TargetLevelSetting:
    role: str
    domain: str
    # Three-stakeholder inputs
    business_owner_target: int          # 0-3
    role_incumbent_target: int          # 0-3 (average of incumbents surveyed)
    ld_feasibility_ceiling: int         # 0-3: what's achievable in 12 months from current level
    current_average_level: float        # assessed current level

    def recommended_target(self) -> int:
        """Conservative: use the minimum of stakeholder inputs, capped at feasibility."""
        stakeholder_consensus = min(self.business_owner_target, self.role_incumbent_target)
        return min(stakeholder_consensus, self.ld_feasibility_ceiling)

    def gap_at_recommended_target(self) -> float:
        return max(0.0, self.recommended_target() - self.current_average_level)

    def rationale(self) -> str:
        target = self.recommended_target()
        if self.ld_feasibility_ceiling < min(self.business_owner_target,
                                              self.role_incumbent_target):
            return (
                f"Target capped at {target} (Level {self.ld_feasibility_ceiling}) by L&D feasibility. "
                f"Business owner requested {self.business_owner_target}, incumbents requested "
                f"{self.role_incumbent_target}. Revisit in 12 months."
            )
        return (
            f"Target {target} agreed by all stakeholders. "
            f"Estimated gap from current average {self.current_average_level:.1f}: "
            f"{self.gap_at_recommended_target():.1f} levels."
        )

setting = TargetLevelSetting(
    role="team_lead",
    domain="change_leadership",
    business_owner_target=3,
    role_incumbent_target=2,
    ld_feasibility_ceiling=2,
    current_average_level=0.85,
)
print(f"Recommended target: {setting.recommended_target()}")
print(setting.rationale())
